#include<bits/stdc++.h>
using namespace std;
string s[21];
string bm;
int hd[256];
int mp[16],all[21][21];
void solve(string &s1,int p)
{
	int h;
	for(int i=0;i<s1.length();i+=2)
	{
		if(s1[i]>='A') h=16*(s1[i]-'A'+10);
		else h=16*(s1[i]-'0');
		if(s1[i+1]>='A') h+=s1[i+1]-'A'+10;
		else h+=s1[i+1]-'0';
		hd[h]++;
		all[p][i/2]=h;
		
	}
}
int main()
{
	int n,t,a;
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>s[i];
		solve(s[i],i);
	}
	for(int k=0;k<16;k++)
	{
		t=hd[0],a=0;
		for(int i=0;i<256;i++)
		{
			if(hd[i]>t) t=hd[i],a=i;
		}
		mp[k]=a;
		hd[a]=0;	
	}
	for(int k=0;k<16;k++)
	{
		int x=mp[k]/16;
		if(x>9) cout<<char('A'+x-10);
		else  cout<<x;
		x=mp[k]%16;
		if(x>9) cout<<char('A'+x-10);
		else  cout<<x;
	}
	cout<<endl;
	for(int p=1;p<=n;p++)
	{
		for(int i=0;i<s[p].length();i+=2){
			int mn=abs(all[p][i/2]-mp[0]),a=0;
			for(int k=0;k<16;k++)
			{
				if(mn>abs(all[p][i/2]-mp[k]))mn=abs(all[p][i/2]-mp[k]),a=k;
			}
			int x=a%16;
			if(x>9) cout<<char('A'+x-10);
			else  cout<<x;
		}
		cout<<endl;
	}
	return 0;
}
